class Solution {
public:
    bool canConvertString(string s, string t, int k) {
        if (s.size() != t.size()) return false;
        vector<int> count(26, 0);
        for (int i = 0; i < s.size(); ++i) {
            int diff = (t[i] - s[i] + 26) % 26;
            count[diff]++;
        }
        int maxMove = 0;
        for (int i = 1; i < 26; ++i) {
            if (count[i]) {
                maxMove = max(maxMove, i + 26 * (count[i] - 1));
            }
        }
        return maxMove <= k;
    }
};
